package com.sudhir.localeasy1.ui.activities

import android.os.Bundle
import android.view.View
import android.widget.Button
import android.widget.Toast
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.Observer
import com.google.firebase.auth.FirebaseAuth
import com.sudhir.localeasy1.databinding.ActivityBookingBinding
import com.sudhir.localeasy1.ui.viewmodel.BookingViewModel
import java.util.*

class BookingActivity : AppCompatActivity() {

    private lateinit var binding: ActivityBookingBinding
    private val bookingViewModel: BookingViewModel by viewModels()
    private var selectedTime: Long? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityBookingBinding.inflate(layoutInflater)
        setContentView(binding.root)

        val serviceId = intent.getStringExtra("service_id") ?: ""
        if (serviceId.isEmpty()) {
            finish()
            return
        }

        setupTimeSlots()
        setupObservers()
        bookingViewModel.loadService(serviceId)
    }

    private fun setupTimeSlots() {
        val calendar = Calendar.getInstance()
        val currentTime = calendar.timeInMillis

        // Generate time slots for next 7 days
        for (day in 0..6) {
            for (hour in 9..17) { // 9 AM to 5 PM
                calendar.timeInMillis = currentTime
                calendar.add(Calendar.DAY_OF_MONTH, day)
                calendar.set(Calendar.HOUR_OF_DAY, hour)
                calendar.set(Calendar.MINUTE, 0)
                calendar.set(Calendar.SECOND, 0)
                calendar.set(Calendar.MILLISECOND, 0)

                val timeSlot = calendar.timeInMillis
                if (timeSlot > currentTime) {
                    addTimeSlotButton(timeSlot)
                }
            }
        }
    }

    private fun addTimeSlotButton(time: Long) {
        val button = Button(this).apply {
            text = android.text.format.DateFormat.format("MMM dd, HH:mm", Date(time)).toString()
            setOnClickListener {
                selectedTime = time
                bookingViewModel.selectTime(time)
                // Update UI to show selected
            }
        }
        binding.timeSlotsGrid.addView(button)
    }

    private fun setupObservers() {
        bookingViewModel.service.observe(this, Observer { service ->
            service?.let {
                binding.serviceNameTextView.text = it.name
                binding.serviceDetailsTextView.text = "${it.category} • ${it.duration} • ₹${it.price}"
            }
        })

        bookingViewModel.isLoading.observe(this, Observer { isLoading ->
            binding.bookButton.isEnabled = !isLoading
            binding.bookButton.text = if (isLoading) "Booking..." else "Complete Booking"
        })

        bookingViewModel.error.observe(this, Observer { error ->
            binding.errorTextView.visibility = if (error != null) View.VISIBLE else View.GONE
            binding.errorTextView.text = error
        })

        bookingViewModel.bookingSuccess.observe(this, Observer { success ->
            if (success) {
                Toast.makeText(this, "Booking successful!", Toast.LENGTH_SHORT).show()
                finish()
            }
        })
    }

    fun onBookButtonClick(view: View) {
        val userId = FirebaseAuth.getInstance().currentUser?.uid ?: ""
        val notes = binding.notesEditText.text.toString()

        if (selectedTime == null) {
            Toast.makeText(this, "Please select a time slot", Toast.LENGTH_SHORT).show()
            return
        }

        bookingViewModel.createBooking(userId, notes)
    }
}

package com.sudhir.localeasy1.ui.activities

import android.os.Bundle
import android.view.View
import android.widget.Button
import android.widget.Toast
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.Observer
import com.google.firebase.auth.FirebaseAuth
import com.sudhir.localeasy1.databinding.ActivityBookingBinding
import com.sudhir.localeasy1.ui.viewmodel.BookingViewModel
import java.util.*

class BookingActivity : AppCompatActivity() {

    private lateinit var binding: ActivityBookingBinding
    private val bookingViewModel: BookingViewModel by viewModels()
    private var selectedTime: Long? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityBookingBinding.inflate(layoutInflater)
        setContentView(binding.root)

        val serviceId = intent.getStringExtra("service_id") ?: ""
        if (serviceId.isEmpty()) {
            finish()
            return
        }

        setupTimeSlots()
        setupObservers()
        bookingViewModel.loadService(serviceId)
    }

    private fun setupTimeSlots() {
        val calendar = Calendar.getInstance()
        val currentTime = calendar.timeInMillis

        // Generate time slots for next 7 days
        for (day in 0..6) {
            for (hour in 9..17) { // 9 AM to 5 PM
                calendar.timeInMillis = currentTime
                calendar.add(Calendar.DAY_OF_MONTH, day)
                calendar.set(Calendar.HOUR_OF_DAY, hour)
                calendar.set(Calendar.MINUTE, 0)
                calendar.set(Calendar.SECOND, 0)
                calendar.set(Calendar.MILLISECOND, 0)

                val timeSlot = calendar.timeInMillis
                if (timeSlot > currentTime) {
                    addTimeSlotButton(timeSlot)
                }
            }
        }
    }

    private fun addTimeSlotButton(time: Long) {
        val button = Button(this).apply {
            text = android.text.format.DateFormat.format("MMM dd, HH:mm", Date(time)).toString()
            setOnClickListener {
                selectedTime = time
                bookingViewModel.selectTime(time)
                // Update UI to show selected
            }
        }
        binding.timeSlotsGrid.addView(button)
    }

    private fun setupObservers() {
        bookingViewModel.service.observe(this, Observer { service ->
            service?.let {
                binding.serviceNameTextView.text = it.name
                binding.serviceDetailsTextView.text = "${it.category} • ${it.duration} • ₹${it.price}"
            }
        })

        bookingViewModel.isLoading.observe(this, Observer { isLoading ->
            binding.bookButton.isEnabled = !isLoading
            binding.bookButton.text = if (isLoading) "Booking..." else "Complete Booking"
        })

        bookingViewModel.error.observe(this, Observer { error ->
            binding.errorTextView.visibility = if (error != null) View.VISIBLE else View.GONE
            binding.errorTextView.text = error
        })

        bookingViewModel.bookingSuccess.observe(this, Observer { success ->
            if (success) {
                Toast.makeText(this, "Booking successful!", Toast.LENGTH_SHORT).show()
                finish()
            }
        })
    }

    fun onBookButtonClick(view: View) {
        // Check if profile is complete before allowing booking
        val user = FirebaseAuth.getInstance().currentUser
        if (user == null) {
            Toast.makeText(this, "Please login first", Toast.LENGTH_SHORT).show()
            return
        }

        // Check profile completion
        com.google.firebase.firestore.FirebaseFirestore.getInstance()
            .collection("users")
            .document(user.uid)
            .get()
            .addOnSuccessListener { document ->
                val email = user.email ?: ""
                val phone = document.getString("phone") ?: ""

                if (email.isEmpty() || phone.isEmpty()) {
                    Toast.makeText(this, "Complete your profile first (add phone number)", Toast.LENGTH_SHORT).show()
                    return@addOnSuccessListener
                }

                // Profile is complete, proceed with booking
                proceedWithBooking()
            }
            .addOnFailureListener {
                Toast.makeText(this, "Error checking profile: ${it.message}", Toast.LENGTH_SHORT).show()
            }
    }

    private fun proceedWithBooking() {
        val userId = FirebaseAuth.getInstance().currentUser?.uid ?: ""
        val notes = binding.notesEditText.text.toString()

        if (selectedTime == null) {
            Toast.makeText(this, "Please select a time slot", Toast.LENGTH_SHORT).show()
            return
        }

        bookingViewModel.createBooking(userId, notes)
    }
}

package com.sudhir.localeasy1.ui.activities
import android.os.Bundle import android.widget.Toast import androidx.appcompat.app.AppCompatActivity import com.google.firebase.auth.FirebaseAuth import com.google.firebase.firestore.FirebaseFirestore import com.sudhir.localeasy1.databinding.ActivityBookingConfirmBinding
class BookingConfirmActivity : AppCompatActivity() {
private lateinit var binding: ActivityBookingConfirmBinding private val db = FirebaseFirestore.getInstance()
override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) binding = ActivityBookingConfirmBinding.inflate(layoutInflater) setContentView(binding.root)
val serviceName = intent.getStringExtra("serviceName") ?: "Unknown Service" val price = intent.getDoubleExtra("price", 0.0) val serviceId = intent.getStringExtra("serviceId") ?: ""
binding.serviceNameTextView.text = serviceName binding.priceTextView.text = "₹$price"
binding.confirmButton.setOnClickListener { confirmBooking(serviceName, price, serviceId) }
binding.cancelButton.setOnClickListener { finish() } }
private fun confirmBooking(serviceName: String, price: Double, serviceId: String) { val uid = FirebaseAuth.getInstance().currentUser?.uid ?: return
binding.confirmButton.isEnabled = false binding.confirmButton.text = "Confirming..."
val booking = hashMapOf( "userId" to uid, "serviceName" to serviceName, "serviceId" to serviceId, "price" to price, "status" to "pending", "date" to java.text.SimpleDateFormat("yyyy-MM-dd", java.util.Locale.getDefault()).format(java.util.Date()), "time" to java.text.SimpleDateFormat("HH:mm", java.util.Locale.getDefault()).format(java.util.Date()), "createdAt" to System.currentTimeMillis() )
db.collection("bookings") .add(booking) .addOnSuccessListener { Toast.makeText(this, "Booking confirmed!", Toast.LENGTH_SHORT).show() finish() } .addOnFailureListener { e -> Toast.makeText(this, "Error: ${e.message}", Toast.LENGTH_SHORT).show() binding.confirmButton.isEnabled = true binding.confirmButton.text = "Confirm Booking" } } }

package com.sudhir.localeasy1.ui.activities
import android.os.Bundle import android.widget.Toast import androidx.appcompat.app.AppCompatActivity import com.google.firebase.auth.FirebaseAuth import com.google.firebase.firestore.FirebaseFirestore import com.sudhir.localeasy1.databinding.ActivityCreateOfferBinding
class CreateOfferActivity : AppCompatActivity() {
private lateinit var binding: ActivityCreateOfferBinding private val db = FirebaseFirestore.getInstance()
override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) binding = ActivityCreateOfferBinding.inflate(layoutInflater) setContentView(binding.root)
setupClickListener() }
private fun setupClickListener() { binding.submitButton.setOnClickListener { val title = binding.titleEditText.text.toString().trim() val description = binding.descriptionEditText.text.toString().trim() val discount = binding.discountEditText.text.toString().trim()
if (title.isEmpty() || description.isEmpty() || discount.isEmpty()) { Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show() return@setOnClickListener }
binding.submitButton.isEnabled = false binding.submitButton.text = "Creating..."
val uid = FirebaseAuth.getInstance().currentUser?.uid ?: "" val offer = mutableMapOf<String, Any>() offer["title"] = title offer["description"] = description offer["discount"] = discount.toIntOrNull() ?: 0 offer["businessId"] = uid offer["createdAt"] = System.currentTimeMillis()
db.collection("offers") .add(offer) .addOnSuccessListener { Toast.makeText(this, "Offer created successfully!", Toast.LENGTH_SHORT).show() finish() } .addOnFailureListener { e -> Toast.makeText(this, "Error: ${e.message}", Toast.LENGTH_SHORT).show() binding.submitButton.isEnabled = true binding.submitButton.text = "Create Offer" } } } }

package com.sudhir.localeasy1.ui.activities

import android.content.Intent
import android.os.Bundle
import android.view.View
import android.widget.Toast
import androidx.activity.viewModels
import androidx.appcompat.app.AppCompatActivity
import androidx.lifecycle.Observer
import com.sudhir.localeasy1.MainActivity
import com.sudhir.localeasy1.databinding.ActivityLoginBinding
import com.sudhir.localeasy1.ui.viewmodel.AuthViewModel

class LoginActivity : AppCompatActivity() {

    private lateinit var binding: ActivityLoginBinding
    private val authViewModel: AuthViewModel by viewModels()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        binding = ActivityLoginBinding.inflate(layoutInflater)
        setContentView(binding.root)

        setupObservers()
        setupClickListeners()
    }

    private fun setupObservers() {
        authViewModel.isLoading.observe(this, Observer { isLoading ->
            binding.loginButton.isEnabled = !isLoading
            binding.loginButton.text = if (isLoading) "Signing In..." else "Sign In"
        })

        authViewModel.error.observe(this, Observer { error ->
            binding.errorTextView.visibility = if (error != null) View.VISIBLE else View.GONE
            binding.errorTextView.text = error
        })

        authViewModel.isLoggedIn.observe(this, Observer { isLoggedIn ->
            if (isLoggedIn) {
                navigateToMain()
            }
        })
    }

    private fun setupClickListeners() {
        binding.loginButton.setOnClickListener {
            val email = binding.emailEditText.text.toString().trim()
            val password = binding.passwordEditText.text.toString().trim()

            if (email.isEmpty() || password.isEmpty()) {
                Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            authViewModel.login(email, password,
                onSuccess = {
                    Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show()
                },
                onError = { error ->
                    Toast.makeText(this, error, Toast.LENGTH_SHORT).show()
                }
            )
        }

        binding.signupButton.setOnClickListener {
            startActivity(Intent(this, SignupActivity::class.java))
        }
    }

    private fun navigateToMain() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }
}

