        private const val VIEW_TYPE_USER = 1
        private const val VIEW_TYPE_ADMIN = 2
    }

    override fun getItemViewType(position: Int): Int {
        return if (isAdmin) VIEW_TYPE_ADMIN else VIEW_TYPE_USER
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
        val inflater = LayoutInflater.from(parent.context)
        return if (viewType == VIEW_TYPE_ADMIN) {
            val binding = ItemServiceAdminBinding.inflate(inflater, parent, false)
            AdminServiceViewHolder(binding)
        } else {
            val binding = ItemServiceBinding.inflate(inflater, parent, false)
            ServiceViewHolder(binding)
        }
    }

    override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
        val service = services[position]
        if (holder is AdminServiceViewHolder) {
            holder.bind(service)
        } else if (holder is ServiceViewHolder) {
            holder.bind(service)
        }
    }

    override fun getItemCount(): Int = services.size

    fun updateList(newList: List<Service>) {
        services = newList
        notifyDataSetChanged()
    }

    inner class ServiceViewHolder(private val binding: ItemServiceBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(service: Service) {
            binding.serviceNameTextView.text = service.name
            binding.serviceCategoryTextView.text = service.category
            binding.serviceDurationTextView.text = "Duration: ${service.duration}"
            binding.servicePriceTextView.text = "₹${service.price}"

            binding.bookButton.setOnClickListener {
                val intent = Intent(binding.root.context, BookingConfirmActivity::class.java).apply {
                    putExtra("serviceId", service.id)
                    putExtra("businessId", service.businessId)
                    putExtra("serviceName", service.name)
                    putExtra("price", service.price.toDouble())
                }
                binding.root.context.startActivity(intent)
            }
        }
    }

    inner class AdminServiceViewHolder(private val binding: ItemServiceAdminBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(service: Service) {
            binding.serviceNameTextView.text = service.name
            binding.serviceCategoryTextView.text = service.category
            binding.serviceDurationTextView.text = service.duration
            binding.servicePriceTextView.text = "₹${service.price}"

            binding.editBtn.setOnClickListener {
                onEditClick(service)
            }

            binding.deleteBtn.setOnClickListener {
                onDeleteClick(service)
            }
        }
    }
}

package com.sudhir.localeasy1.ui.adapters

import android.content.Intent
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.view.animation.AnimationUtils
import androidx.recyclerview.widget.RecyclerView
import com.sudhir.localeasy1.R
import com.sudhir.localeasy1.data.Service
import com.sudhir.localeasy1.databinding.ItemServiceBinding
import com.sudhir.localeasy1.databinding.ItemServiceAdminBinding
import com.sudhir.localeasy1.ui.activities.BookingConfirmActivity

class ServiceAdapter(
    private var services: List<Service>,
    private val isAdmin: Boolean = false,
    private val onServiceClick: (Service) -> Unit = {},
    private val onEditClick: (Service) -> Unit = {},
    private val onDeleteClick: (Service) -> Unit = {}
) : RecyclerView.Adapter<RecyclerView.ViewHolder>() {

    companion object {
        private const val VIEW_TYPE_USER = 1
        private const val VIEW_TYPE_ADMIN = 2
    }

    override fun getItemViewType(position: Int): Int {
        return if (isAdmin) VIEW_TYPE_ADMIN else VIEW_TYPE_USER
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): RecyclerView.ViewHolder {
        val inflater = LayoutInflater.from(parent.context)
        return if (viewType == VIEW_TYPE_ADMIN) {
            val binding = ItemServiceAdminBinding.inflate(inflater, parent, false)
            AdminServiceViewHolder(binding)
        } else {
            val binding = ItemServiceBinding.inflate(inflater, parent, false)
            ServiceViewHolder(binding)
        }
    }

    override fun onBindViewHolder(holder: RecyclerView.ViewHolder, position: Int) {
        val service = services[position]
        if (holder is AdminServiceViewHolder) {
            holder.bind(service)
        } else if (holder is ServiceViewHolder) {
            holder.bind(service)
        }
    }

    override fun getItemCount(): Int = services.size

    fun updateList(newList: List<Service>) {
        services = newList
        notifyDataSetChanged()
    }

    inner class ServiceViewHolder(private val binding: ItemServiceBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(service: Service) {
            binding.serviceNameTextView.text = service.name
            binding.serviceCategoryTextView.text = service.category
            binding.serviceDurationTextView.text = "Duration: ${service.duration}"
            binding.servicePriceTextView.text = "₹${service.price}"

            // Apply fade-in animation
            val fadeInAnim = AnimationUtils.loadAnimation(binding.root.context, R.anim.fade_in)
            binding.root.startAnimation(fadeInAnim)

            binding.bookButton.setOnClickListener {
                // Scale animation on button click
                it.animate()
                    .scaleX(0.95f)
                    .scaleY(0.95f)
                    .setDuration(100)
                    .withEndAction {
                        it.animate()
                            .scaleX(1f)
                            .scaleY(1f)
                            .setDuration(100)
                            .start()
                    }
                    .start()

                val intent = Intent(binding.root.context, BookingConfirmActivity::class.java).apply {
                    putExtra("serviceId", service.id)
                    putExtra("businessId", service.businessId)
                    putExtra("serviceName", service.name)
                    putExtra("price", service.price.toDouble())
                }
                binding.root.context.startActivity(intent)
            }

            binding.root.setOnClickListener { onServiceClick(service) }
        }
    }

    inner class AdminServiceViewHolder(private val binding: ItemServiceAdminBinding) :
        RecyclerView.ViewHolder(binding.root) {

        fun bind(service: Service) {
            binding.serviceNameTextView.text = service.name
            binding.serviceCategoryTextView.text = service.category
            binding.serviceDurationTextView.text = service.duration
            binding.servicePriceTextView.text = "₹${service.price}"

            binding.editBtn.setOnClickListener {
                onEditClick(service)
            }

            binding.deleteBtn.setOnClickListener {
                onDeleteClick(service)
            }
        }
    }
}

package com.sudhir.localeasy1.ui.fragments

import android.os.Bundle
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.recyclerview.widget.LinearLayoutManager
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.sudhir.localeasy1.R
import com.sudhir.localeasy1.databinding.FragmentBookingBinding
import com.sudhir.localeasy1.ui.adapters.BookingAdapter
import com.sudhir.localeasy1.data.Booking

class BookingFragment : Fragment() {

    private var _binding: FragmentBookingBinding? = null
    private val binding get() = _binding!!
    private lateinit var bookingAdapter: BookingAdapter
    private val bookings = mutableListOf<Booking>()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentBookingBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        setupRecyclerView()
        loadUserBookings()
    }

    private fun setupRecyclerView() {
        bookingAdapter = BookingAdapter(bookings)
        binding.bookingsRecyclerView.layoutManager = LinearLayoutManager(requireContext())
        binding.bookingsRecyclerView.adapter = bookingAdapter
    }

    private fun loadUserBookings() {
        val uid = FirebaseAuth.getInstance().currentUser?.uid ?: return

        binding.progressBar.visibility = View.VISIBLE
        binding.emptyTextView.visibility = View.GONE

        FirebaseFirestore.getInstance()
            .collection("bookings")
            .whereEqualTo("userId", uid)
            .orderBy("createdAt", com.google.firebase.firestore.Query.Direction.DESCENDING)
            .get()
            .addOnSuccessListener { result ->
                binding.progressBar.visibility = View.GONE
                bookings.clear()

                if (result.isEmpty) {
                    binding.emptyTextView.visibility = View.VISIBLE
                    binding.emptyTextView.text = "No bookings found"
                } else {
                    binding.emptyTextView.visibility = View.GONE
                    for (doc in result) {
                        try {
                            val booking = Booking(
                                id = doc.id,
                                userId = doc.getString("userId") ?: "",
                                serviceId = doc.getString("serviceId") ?: "",
                                serviceName = doc.getString("serviceName") ?: "Unknown Service",
                                time = doc.getLong("time") ?: System.currentTimeMillis(),
                                status = doc.getString("status") ?: "pending"
                            )
                            bookings.add(booking)
                        } catch (e: Exception) {
                            Log.e("BookingFragment", "Error parsing booking", e)
                        }
                    }
                    bookingAdapter.notifyDataSetChanged()
                }
            }
            .addOnFailureListener { e ->
                binding.progressBar.visibility = View.GONE
                binding.emptyTextView.visibility = View.VISIBLE
                binding.emptyTextView.text = "Error loading bookings"
                Log.e("BookingFragment", "Error loading bookings", e)
                Toast.makeText(requireContext(), "Error loading bookings: ${e.message}", Toast.LENGTH_SHORT).show()
            }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

        super.onDestroyView()
        _binding = null
    }
}

package com.sudhir.localeasy1.ui.fragments

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.LinearLayout
import android.widget.Toast
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.Observer
import androidx.recyclerview.widget.LinearLayoutManager
import com.google.firebase.firestore.FirebaseFirestore
import com.sudhir.localeasy1.R
import com.sudhir.localeasy1.databinding.FragmentHomeBinding
import com.sudhir.localeasy1.ui.activities.BookingConfirmActivity
import com.sudhir.localeasy1.ui.adapters.ServiceAdapter
import com.sudhir.localeasy1.ui.viewmodel.HomeViewModel

class HomeFragment : Fragment() {

    private var _binding: FragmentHomeBinding? = null
    private val binding get() = _binding!!
    private val homeViewModel: HomeViewModel by viewModels()
    private lateinit var serviceAdapter: ServiceAdapter
    private val db = FirebaseFirestore.getInstance()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentHomeBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        try {
            Log.d("HomeFragment", "onViewCreated started")
            setupRecyclerView()
            setupCategoryButtons()
            setupObservers()
            loadApprovedOfferPromo()
            Log.d("HomeFragment", "Setup completed")
        } catch (e: Exception) {
            Log.e("HomeFragment", "Error in onViewCreated", e)
            Toast.makeText(requireContext(), "Error loading home screen: ${e.message}", Toast.LENGTH_LONG).show()
        }
    }

    private fun setupRecyclerView() {
        try {
            serviceAdapter = ServiceAdapter(emptyList()) { service ->
                val intent = Intent(requireContext(), BookingConfirmActivity::class.java).apply {
                    putExtra("serviceId", service.id)
                    putExtra("serviceName", service.name)
                    putExtra("price", service.price.toDouble())
                    putExtra("businessId", service.businessId)
                }
                startActivity(intent)
            }
            binding.servicesRecyclerView.layoutManager = LinearLayoutManager(requireContext())
            binding.servicesRecyclerView.adapter = serviceAdapter
            Log.d("HomeFragment", "RecyclerView setup completed")
        } catch (e: Exception) {
            Log.e("HomeFragment", "Error setting up RecyclerView", e)
        }
    }

    private fun setupCategoryButtons() {
        try {
            homeViewModel.categories.observe(viewLifecycleOwner, Observer { categories ->
                Log.d("HomeFragment", "Categories loaded: ${categories.size}")
                binding.categoriesContainer.removeAllViews()
                categories.forEach { category ->
                    try {
                        val button = Button(requireContext()).apply {
                            text = category
                            setBackgroundResource(R.drawable.category_chip_bg)
                            setTextColor(resources.getColor(R.color.text_primary))
                            textSize = 14f
                            setPadding(16, 8, 16, 8)
                            setOnClickListener {
                                Log.d("HomeFragment", "Category clicked: $category")
                                if (category == "All") {
                                    homeViewModel.loadAllServices()
                                } else {
                                    homeViewModel.loadServicesByCategory(category)
                                }
                            }
                        }
                        val params = LinearLayout.LayoutParams(
                            LinearLayout.LayoutParams.WRAP_CONTENT,
                            LinearLayout.LayoutParams.WRAP_CONTENT
                        ).apply {
                            marginEnd = 8
                        }
                        button.layoutParams = params
                        binding.categoriesContainer.addView(button)
                    } catch (e: Exception) {
                        Log.e("HomeFragment", "Error creating category button", e)
                    }
                }
            })
        } catch (e: Exception) {
            Log.e("HomeFragment", "Error setting up category buttons", e)
        }
    }

    private fun setupObservers() {
        try {
            homeViewModel.services.observe(viewLifecycleOwner, Observer { services ->
                Log.d("HomeFragment", "Services loaded: ${services.size}")
                try {
                    serviceAdapter = ServiceAdapter(services) { service ->
                        // Navigate to booking confirmation
                        val intent = Intent(requireContext(), BookingConfirmActivity::class.java).apply {
                            putExtra("serviceName", service.name)
                            putExtra("price", service.price.toDouble())
                            putExtra("serviceId", service.id)
                            putExtra("businessId", service.businessId)
                        }
                        startActivity(intent)
                    }
                    binding.servicesRecyclerView.adapter = serviceAdapter
                } catch (e: Exception) {
                    Log.e("HomeFragment", "Error updating adapter", e)
                }
            })

            homeViewModel.isLoading.observe(viewLifecycleOwner, Observer { isLoading ->
                Log.d("HomeFragment", "Loading state: $isLoading")
                // Show/hide loading indicator if needed
            })

            homeViewModel.error.observe(viewLifecycleOwner, Observer { error ->
                error?.let {
                    Log.e("HomeFragment", "Error: $it")
                    Toast.makeText(requireContext(), it, Toast.LENGTH_SHORT).show()
                }
            })
        } catch (e: Exception) {
            Log.e("HomeFragment", "Error setting up observers", e)
        }
    }

    private fun loadApprovedOfferPromo() {
        db.collection("offers")
            .get()
            .addOnSuccessListener { result ->
                result.documents.forEach { offerDoc ->
                    val businessId = offerDoc.getString("businessId") ?: return@forEach
                    db.collection("businesses")
                        .document(businessId)
                        .get()
                        .addOnSuccessListener { businessDoc ->
                            if (businessDoc.getBoolean("approved") == true) {
                                val title = offerDoc.getString("title") ?: "Special Offer"
                                val discount = offerDoc.getLong("discount")?.toInt()
                                    ?: (offerDoc.getDouble("discount")?.toInt() ?: 0)
                                binding.promoTitleTextView.text = title
                                binding.promoSubtitleTextView.text = "Get $discount% off on selected services"
                                return@addOnSuccessListener
                            }
                        }
                }
            }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.sudhir.localeasy1.ui.fragments

import android.content.Intent
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.fragment.app.Fragment
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.sudhir.localeasy1.R
import com.sudhir.localeasy1.databinding.FragmentProfileBinding
import com.sudhir.localeasy1.ui.activities.LoginActivity

class ProfileFragment : Fragment() {

    private var _binding: FragmentProfileBinding? = null
    private val binding get() = _binding!!
    private val auth = FirebaseAuth.getInstance()
    private val db = FirebaseFirestore.getInstance()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentProfileBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        loadUserProfile()
        setupClickListeners()
    }

    private fun loadUserProfile() {
        val user = auth.currentUser ?: return

        binding.emailTextView.text = user.email ?: "No email"

        // Load additional profile data from Firestore
        db.collection("users").document(user.uid)
            .get()
            .addOnSuccessListener { document ->
                if (document.exists()) {
                    binding.nameTextView.text = document.getString("name") ?: "No name"
                    binding.phoneTextView.text = document.getString("phone") ?: "No phone"
                } else {
                    binding.nameTextView.text = "No name"
                    binding.phoneTextView.text = "No phone"
                }
            }
            .addOnFailureListener { e ->
                Toast.makeText(requireContext(), "Error loading profile: ${e.message}", Toast.LENGTH_SHORT).show()
                binding.nameTextView.text = "Error loading name"
                binding.phoneTextView.text = "Error loading phone"
            }
    }

    private fun setupClickListeners() {
        binding.editProfileButton.setOnClickListener {
            // TODO: Implement profile editing
            Toast.makeText(requireContext(), "Profile editing coming soon", Toast.LENGTH_SHORT).show()
        }

        binding.logoutButton.setOnClickListener {
            auth.signOut()
            startActivity(Intent(requireContext(), LoginActivity::class.java))
            requireActivity().finish()
        }
    }

    // Utility function to check if profile is complete
    fun isProfileComplete(): Boolean {
        val user = auth.currentUser ?: return false
        val email = user.email
        val phone = binding.phoneTextView.text.toString()

        return !email.isNullOrEmpty() && phone != "No phone" && phone.isNotEmpty()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

package com.sudhir.localeasy1.ui.viewmodel

import android.util.Log
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sudhir.localeasy1.data.Service
import com.sudhir.localeasy1.repository.ServiceRepository
import kotlinx.coroutines.launch

class HomeViewModel : ViewModel() {
    private val serviceRepository = ServiceRepository()

    private val _services = MutableLiveData<List<Service>>()
    val services: LiveData<List<Service>> = _services

    private val _categories = MutableLiveData<List<String>>()
    val categories: LiveData<List<String>> = _categories

    private val _isLoading = MutableLiveData(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    init {
        loadServices()
        loadCategories()
    }

    private fun loadServices() {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val serviceList = serviceRepository.getAllServices()
                // If no services from Firebase, provide sample data
                if (serviceList.isEmpty()) {
                    _services.value = getSampleServices()
                } else {
                    _services.value = serviceList
                }
            } catch (e: Exception) {
                // If Firebase fails, show sample data
                _error.value = "Using offline data: ${e.message}"
                _services.value = getSampleServices()
            } finally {
                _isLoading.value = false
            }
        }
    }

    private fun loadCategories() {
        // Sample categories - in real app, fetch from backend
        _categories.value = listOf("Salon", "Clinic", "Gym", "Spa", "Restaurant", "Cleaning")
    }

    fun loadServicesByCategory(category: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val serviceList = serviceRepository.getServicesByCategory(category)
                Log.d("FIRESTORE", "Docs for $category: ${serviceList.size}")
                // If no services from Firebase, filter sample data
                if (serviceList.isEmpty()) {
                    _services.value = getSampleServices().filter { it.category == category }
                } else {
                    _services.value = serviceList
                }
            } catch (e: Exception) {
                // If Firebase fails, filter sample data
                _error.value = "Using offline data: ${e.message}"
                _services.value = getSampleServices().filter { it.category == category }
            } finally {
                _isLoading.value = false
            }
        }
    }

    private fun getSampleServices(): List<Service> {
        return listOf(
            Service(
                id = "1",
                name = "Hair Cut & Styling",
                price = 500,
                duration = "45 mins",
                category = "Salon",
                businessId = "biz1"
            ),
            Service(
                id = "2",
                name = "General Checkup",
                price = 800,
                duration = "30 mins",
                category = "Clinic",
                businessId = "biz2"
            ),
            Service(
                id = "3",
                name = "Gym Membership",
                price = 2000,
                duration = "1 month",
                category = "Gym",
                businessId = "biz3"
            ),
            Service(
                id = "4",
                name = "Swedish Massage",
                price = 1500,
                duration = "60 mins",
                category = "Spa",
                businessId = "biz1"
            ),
            Service(
                id = "5",
                name = "Home Cleaning",
                price = 1200,
                duration = "2 hours",
                category = "Cleaning",
                businessId = "biz4"
            )
        )
    }
}

package com.sudhir.localeasy1.ui.viewmodel

import android.util.Log
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sudhir.localeasy1.data.Service
import com.sudhir.localeasy1.repository.ServiceRepository
import kotlinx.coroutines.launch

class HomeViewModel : ViewModel() {
    private val serviceRepository = ServiceRepository()

    private val _services = MutableLiveData<List<Service>>()
    val services: LiveData<List<Service>> = _services

    private val _categories = MutableLiveData<List<String>>()
    val categories: LiveData<List<String>> = _categories

    private val _isLoading = MutableLiveData(false)
    val isLoading: LiveData<Boolean> = _isLoading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    init {
        loadServices()
        loadCategories()
    }

    private fun loadServices() {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val serviceList = serviceRepository.getAllServices()
                _services.value = serviceList
            } catch (e: Exception) {
                _error.value = "Error loading services: ${e.message}"
                _services.value = emptyList()
            } finally {
                _isLoading.value = false
            }
        }
    }

    private fun loadCategories() {
        // Sample categories - in real app, fetch from backend
        _categories.value = listOf("All", "Salon", "Clinic", "Gym", "Spa", "Restaurant", "Cleaning")
    }

    fun loadServicesByCategory(category: String) {
        viewModelScope.launch {
            _isLoading.value = true
            _error.value = null
            try {
                val serviceList = serviceRepository.getServicesByCategory(category)
                Log.d("HomeViewModel", "Category: $category, Found services: ${serviceList.size}")
                for (service in serviceList) {
                    Log.d("HomeViewModel", "Service: ${service.name}, Category: ${service.category}, BusinessId: ${service.businessId}")
                }
                // Show only real data from database - no sample data fallback
                _services.value = serviceList
            } catch (e: Exception) {
                Log.e("HomeViewModel", "Error loading services for category $category", e)
                _error.value = "Error loading services: ${e.message}"
                _services.value = emptyList()
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun loadAllServices() {
        loadServices()
    }
}
